-- Enrichment marathon batch: PrivyDrop, Process Street, ProcessWire, Procore, Procurify, ProdPad, Product Fruits, Productboard

-- ── PrivyDrop ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PrivyDrop is a free, open-source, peer-to-peer file and clipboard sharing web app that moves files directly between devices using WebRTC, with no account, upload limit, or server storage.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (MIT license); no paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Solo developer / independent open-source project$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$, $q$Spanish$q$, $q$Japanese$q$, $q$German$q$, $q$French$q$, $q$Korean$q$]::text[],
  seo_title = COALESCE($q$PrivyDrop Review 2026: Free P2P File and Clipboard Sharing$q$, seo_title),
  seo_meta_description = COALESCE($q$PrivyDrop is a free, open-source WebRTC tool for encrypted peer-to-peer file and clipboard sharing with no signup, size limits, or server storage. See features and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PrivyDrop is a free, open-source, browser-based file and clipboard sharing tool built on WebRTC peer-to-peer technology. It positions itself as a privacy-first alternative to AirDrop that works across any modern browser and operating system rather than being locked to a single device ecosystem. The core idea is that files, folders, images, and rich text never pass through or get stored on a central server; instead, data moves directly between the sender and receiver's devices over an encrypted peer-to-peer connection established via a shared link or scanned QR code. Because there is no server-side relay for the actual file content, PrivyDrop advertises unlimited file size and transfer speed limited only by the users' own network connection, along with support for resumable transfers if a connection drops mid-transfer and the ability to send entire folders rather than single files at a time. The project also includes a clipboard-sharing mode that lets users send and receive formatted rich text instantly between devices, which is useful for quickly moving notes, code snippets, or links across a phone and a laptop without email or a chat app. PrivyDrop is developed and maintained by an independent developer using the GitHub handle david-bai00, who has described building the project partly as a personal solution for frictionless file transfer between their own devices and partly as a hands-on learning exercise in full-stack development. The source code is hosted publicly on GitHub under the MIT license, meaning anyone can inspect, self-host, fork, or modify the application; the stack is built with Next.js, React, Node.js, Express, WebRTC, and Socket.IO, and the project supports Docker-based deployment for teams or individuals who want to run their own instance instead of using the hosted version at privydrop.app. Because the project is free, open source, and run by an individual developer rather than a registered company, there is no publicly disclosed founding date, headquarters, funding history, or company size in the traditional sense - it functions more like a community open-source utility than a commercial SaaS vendor. There is no pricing page, subscription plan, or paid tier; the hosted web app at privydrop.app is entirely free to use, with no registration, file-size cap, or watermarking. The interface supports multiple languages including English, Chinese, Spanish, Japanese, German, French, and Korean, reflecting an international user base drawn largely from privacy-conscious individuals, freelancers, and small teams who need a quick, no-install way to move files between a desktop and a phone or between two people without relying on cloud storage intermediaries like Google Drive or WeTransfer. Because it has no company backing, users evaluating it for business-critical or compliance-sensitive workflows should weigh the lack of formal support, SLAs, or vendor accountability against its strong technical privacy properties.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7cb48bdf-2a61-44e4-8397-27e42d5d763d';

