-- ── Productboard ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Productboard is a customer-driven product management platform that helps teams collect and analyze feedback, prioritize features, and build and share product roadmaps.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, tiered per-maker subscription pricing, billed monthly or annually$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans from $19/maker/month (Plus, billed annually)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Approximately 330-340 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (with a significant presence in Prague, Czech Republic)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Productboard Review 2026: Product Management Software Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Productboard is a customer-driven product management platform for feedback, prioritization, and roadmapping. Compare Productboard pricing plans, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Productboard is a product management platform founded in 2014 by Hubert Palan and Daniel Hejl, dual-headquartered between San Francisco, California, and Prague, Czech Republic, with additional offices in Vancouver, Dublin, London, and Brno alongside a distributed remote team across Europe. Hubert Palan, who grew up in Prague and later moved to the San Francisco Bay Area, serves as founder and CEO; he holds a computer science degree from Czech Technical University in Prague and an MBA in entrepreneurship from UC Berkeley. Productboard's core positioning is 'customer-driven product management': the platform is designed to help product teams systematically capture feedback and feature requests from customers, sales teams, and support tickets, score and prioritize that input against strategic objectives, and translate prioritized work into shareable roadmaps that align engineering, sales, and executive stakeholders. Its main functional areas include a centralized feedback inbox for aggregating input from multiple channels, an insights and scoring engine for prioritizing features against customer and business impact, visual roadmap building and sharing tools including public-facing product portals, and integrations with tools like Salesforce, Jira, Slack, and Zendesk. The company has raised approximately $261.7 million in total funding across seven rounds, most recently a $125 million Series D round in 2022 that valued the company at approximately $1.7 billion, making it one of the more highly valued companies in the product management software category alongside competitors like Aha!. Productboard's differentiator has increasingly become AI: the platform includes an AI feature branded 'Spark' that helps summarize feedback, generate insights, and support prioritization decisions using a credit-based usage system built into its pricing tiers. As of recent estimates, Productboard reported roughly $71.8 million in annual recurring revenue and employs somewhere between approximately 330 and 340 people. Productboard's pricing follows a freemium, per-'maker' model, where a 'maker' is a paid seat for someone actively creating or managing product plans, while unlimited free contributor and viewer-type access is available depending on the tier. The Free plan includes 50 AI credits per month, full access to the Spark AI features, unlimited roadmaps, up to 500 feedback notes, 25 contributors, and one teamspace and product portal, with no credit card required to start. The Plus plan costs $19 per maker per month when billed annually (or $25 per maker per month billed monthly) and adds increased AI credits, customer segmentation, feedback loop closing, and product usage integrations. The Business plan, Productboard's most commonly recommended tier, costs $59 per maker per month billed annually (minimum two makers) or $75 per maker per month billed monthly, and includes unlimited feedback notes, unlimited teamspaces, a shared skills library, two product portals, and enhanced customization. The Enterprise plan is custom priced with a minimum of five makers billed annually and includes 800 AI credits per maker per month, unlimited contributors, SAML SSO, SCIM provisioning, custom roles, Salesforce integration, and live onboarding support. Annual billing saves roughly 21 percent compared to monthly billing across paid tiers, a 14-day free trial is available on the Business plan, and additional AI credit top-ups can be purchased separately if a team exceeds its plan's monthly allotment.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '44247eb4-4fad-4252-a448-315159706699';

