INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Peer-to-peer WebRTC transfer$q$, $q$Files move directly between sender and receiver devices over an encrypted WebRTC connection rather than being uploaded to a central server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$No account required$q$, $q$Users can send and receive files immediately via a shared link or QR code, without signing up or logging in.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Unlimited file size$q$, $q$There is no advertised cap on individual file size; transfer speed depends on the users' own network connection.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Folder transfers$q$, $q$Entire folders can be sent in one transfer rather than selecting files individually.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Resumable transfers$q$, $q$Interrupted transfers can resume rather than restarting from the beginning.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Rich-text clipboard sharing$q$, $q$Users can send and receive formatted text instantly between devices, useful for notes, code, or links.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$QR code and link pairing$q$, $q$Devices connect by scanning a QR code or opening a shared link, making desktop-to-mobile transfers fast.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Open-source and self-hostable$q$, $q$The MIT-licensed source code is on GitHub and can be self-hosted via Docker for full control over the deployment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Completely free with no paid tier or feature paywall$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$No account creation or personal data collection required to use it$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$File content is never stored on a central server, reducing data-exposure risk$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Open-source code can be independently audited or self-hosted$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$No advertised file-size limit$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$No company backing means no formal support channels or SLAs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Founding date, team size, and roadmap are not publicly disclosed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Both devices generally need to be online simultaneously since transfer is peer-to-peer$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Lacks enterprise features like admin controls, audit logs, or centralized user management$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Relies on browser WebRTC support, which can behave inconsistently on some networks or firewalls$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Is PrivyDrop really free?$q$, $q$Yes. PrivyDrop has no paid plans; the hosted web app is free to use with no file-size cap or watermarking.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Does PrivyDrop store my files on a server?$q$, $q$No. Files transfer directly between devices over an encrypted peer-to-peer WebRTC connection and are not stored on PrivyDrop's servers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Do I need to create an account to use PrivyDrop?$q$, $q$No account or login is required. You simply open the site, share a link or QR code, and transfer files.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Can I self-host PrivyDrop?$q$, $q$Yes. The source code is open source under the MIT license and available on GitHub, with Docker support for self-hosting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Is there a file size limit?$q$, $q$PrivyDrop does not advertise a fixed file-size limit; practical limits depend on the devices and network connection involved.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$What happens if my transfer is interrupted?$q$, $q$PrivyDrop supports resumable transfers, so an interrupted transfer can continue rather than starting over.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Who built PrivyDrop?$q$, $q$PrivyDrop is developed and maintained by an independent open-source developer rather than a registered company.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$What languages does PrivyDrop support?$q$, $q$The interface is available in English, Chinese, Spanish, Japanese, German, French, and Korean.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Quick device-to-device transfer$q$, $q$Sending photos, documents, or folders between a phone and a laptop without cables or cloud storage.$q$, $q$Individuals and remote workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Privacy-sensitive file sharing$q$, $q$Sharing sensitive documents without uploading them to a third-party cloud storage provider.$q$, $q$Privacy-conscious professionals and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Ad-hoc collaboration$q$, $q$Quickly sharing a file or clipboard snippet with a colleague or client during a call without account setup.$q$, $q$Small teams and consultants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited peer-to-peer file transfer","Folder transfers","Resumable transfers","Rich-text clipboard sharing","No account required"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PrivyDrop is a free, open-source web application for sharing files, folders, and clipboard content directly between devices using WebRTC peer-to-peer transfer. Rather than uploading a file to a server and generating a download link the way many file-sharing tools do, PrivyDrop establishes a direct encrypted connection between the sender's and receiver's browsers, so the file content itself never touches a third-party server.$q$, $q$The project is built and maintained by an independent developer and distributed under the MIT open-source license, with the full source code available on GitHub. It can be used as a hosted web app at privydrop.app or self-hosted via Docker for teams that want complete control over their own deployment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PrivyDrop's core feature set centers on privacy and simplicity: end-to-end encrypted peer-to-peer transfer with no server-side storage of file content, no account creation, and no advertised limit on file size beyond what the users' network connection can support.$q$, $q$Beyond basic file transfer, PrivyDrop supports whole-folder transfers, resumable uploads if a connection is interrupted, rich-text clipboard sharing for quickly moving formatted notes between devices, and link- or QR-code-based pairing so a desktop and a phone can connect in seconds without typing an address.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PrivyDrop has no pricing plans. The hosted version at privydrop.app is completely free to use, with no premium tier, storage quota, or watermarking.$q$, $q$Because the code is open source under the MIT license, organizations that need more control can self-host PrivyDrop on their own infrastructure at no licensing cost, though they would take on their own hosting and maintenance overhead.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7cb48bdf-2a61-44e4-8397-27e42d5d763d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$No-code workflow builder$q$, $q$Build recurring processes as structured, document-style workflows without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Conditional logic$q$, $q$Workflows branch dynamically based on how earlier steps or form fields are answered.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Forms and file uploads$q$, $q$Embed data-collection forms and file upload fields directly inside workflow steps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Task assignment and due dates$q$, $q$Assign individual steps to specific team members with deadlines and approval gates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Analytics dashboard$q$, $q$Track workflow completion rates, bottlenecks, and process performance over time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Automations and integrations$q$, $q$Connect workflows to other business tools via automation apps, actions, and API access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Slack and Microsoft Teams integration$q$, $q$Trigger and receive workflow notifications directly inside existing collaboration tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Compliance operations support$q$, $q$Templates and structures geared toward audit readiness and regulatory compliance tracking.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Purpose-built for turning recurring processes into trackable, repeatable workflows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Conditional logic allows complex, branching processes without custom development$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Discounted pricing available for qualifying small businesses and non-profits$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Strong fit for compliance and audit-readiness use cases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$14-day free trial with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Exact pricing for Pro and Enterprise plans requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Smaller company size (roughly 55-62 employees) compared to larger workflow platform vendors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Startup plan's per-file storage cap (5MB) is restrictive for larger attachments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Steeper cost jump between Startup and Pro tiers for growing teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$What is Process Street used for?$q$, $q$Process Street is used to document and run recurring business processes such as onboarding, approvals, audits, and compliance checklists as structured, trackable workflows.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$How much does Process Street cost?$q$, $q$Process Street's Startup plan starts around $100/month, Pro around $415/month, and Enterprise around $1,660/month, all with annual billing discounts and custom quotes available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Does Process Street offer a free trial?$q$, $q$Yes, Process Street offers a 14-day free trial on the Pro plan with no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Is there a discount for small businesses or non-profits?$q$, $q$Yes, Process Street offers reduced Pro-plan pricing for businesses under 15 employees and $2 million in revenue, as well as discounts for registered non-profits.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Where is Process Street headquartered?$q$, $q$Process Street is headquartered in San Francisco, California, with additional offices in London and Sydney.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$When was Process Street founded?$q$, $q$Process Street was founded in 2014.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Does Process Street support integrations?$q$, $q$Yes, Process Street offers native automation apps and actions, API access, and integrations with tools like Slack and Microsoft Teams.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Can Process Street handle approval workflows?$q$, $q$Yes, workflows can include approval steps, conditional logic, and task assignment with due dates.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Employee and client onboarding$q$, $q$Standardize onboarding steps with forms, task assignments, and due dates so nothing is missed.$q$, $q$HR and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Compliance and audit readiness$q$, $q$Document and track recurring compliance checklists such as SOC 2 or ISO audit preparation.$q$, $q$Compliance and risk teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Approval and review processes$q$, $q$Route requests such as purchase approvals or content reviews through structured, conditional workflows.$q$, $q$Operations and finance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Startup$q$, $q$$100/month or $1,000/year$q$, $q$Monthly or annual$q$, NULL, $q$["5 paid team members plus 10 guests","Up to 5,000 data set records","Unlimited file storage (5MB per file)","10 automation apps, 100 automation actions/month","Conditional logic, approvals, analytics dashboard"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Pro$q$, $q$$415/month or $5,000/year$q$, $q$Monthly or annual$q$, NULL, $q$["Custom team member and guest limits","Up to 10,000 data set records","100MB per-file storage limit","All automation apps, advanced customization","BI integrations and dedicated success manager"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$Enterprise$q$, $q$$1,660/month or $20,000/year$q$, $q$Monthly or annual$q$, NULL, $q$["Custom user and data limits","Unlimited API calls","Fully managed workflows","Custom integrations","Personalized training and onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Process Street is a no-code workflow and checklist platform, founded in 2014 and based in San Francisco, that helps teams turn recurring business processes into structured, trackable workflows. It is commonly used for employee and client onboarding, approvals, audits, and other repeatable operations where consistency and accountability matter.$q$, $q$The company raised a $12 million Series A round led by Accel in 2020 to expand its no-code workflow builder, and has since leaned further into compliance operations use cases such as audit readiness alongside its core business process management functionality.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Process Street workflows are built from a document-style editor that supports conditional logic, embedded forms, file uploads, task assignment, due dates, and approval steps, so a single workflow can branch and route based on how earlier steps were answered.$q$, $q$The platform includes an analytics dashboard for tracking workflow completion and bottlenecks, native automation apps and actions for connecting to other tools, API access for custom integrations, and direct integrations with collaboration tools like Slack and Microsoft Teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Process Street offers three tiers: Startup (around $100/month or $1,000/year) for small businesses, Pro (around $415/month or $5,000/year) as the most popular plan for growing teams, and Enterprise (around $1,660/month or $20,000/year) for large organizations needing custom limits and managed workflows.$q$, $q$Discounted Pro-plan pricing is available for qualifying small businesses and registered non-profits, and a 14-day free trial requiring no credit card is offered on the Pro plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('14d1d9d1-5e67-4b61-a083-8bace97b6d67', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Flexible fields-and-templates model$q$, $q$Content structure is defined through customizable fields and templates rather than fixed content types, giving developers full control over data structure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$PHP API-first design$q$, $q$A well-documented PHP API lets developers query, manipulate, and render content programmatically without being locked into a rigid theming system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Role-based access control$q$, $q$Granular permissions let administrators control what different user roles can view or edit within the admin interface.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Native multi-language support$q$, $q$Multi-language content and admin interface support is built into the core rather than requiring a third-party plugin.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Modular plugin architecture$q$, $q$An extensive community-maintained module directory allows functionality to be extended without modifying core code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Lightweight, self-hosted core$q$, $q$The core system is lightweight and runs on standard PHP and MySQL/MariaDB hosting, keeping sites fast and portable.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Optional Pro modules$q$, $q$Paid Pro modules from the creator add advanced functionality like enhanced fields, forms, and repeaters for developers who need them.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Active developer community$q$, $q$An established forum and module directory support developers building and maintaining ProcessWire sites.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Completely free and open source with no recurring platform fee$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Highly flexible, developer-friendly API well suited to custom-built websites$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Native multi-language support built into the core$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Lightweight core keeps sites fast and reduces bloat$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Established, active developer community and module ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Requires PHP development knowledge; not designed for non-technical end users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Smaller ecosystem and talent pool compared to mainstream CMS platforms like WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$No official company, support contracts, or SLAs behind the project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Self-hosting means users are responsible for their own hosting, backups, and security updates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Fewer pre-built themes or templates compared to more mainstream CMS platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Is ProcessWire free to use?$q$, $q$Yes, the core ProcessWire CMS and framework are free and open source under the Mozilla Public License 2.0. Optional paid Pro modules are available separately.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Who created ProcessWire?$q$, $q$ProcessWire was created by developer Ryan Cramer, originally as an internal tool for his web development company starting in 2003, before being publicly released as open source in 2010.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Is ProcessWire suitable for non-developers?$q$, $q$ProcessWire is primarily designed for developers who want full control over site structure and code; it is less suited to non-technical users looking for a drag-and-drop website builder.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$What license does ProcessWire use?$q$, $q$ProcessWire is distributed under the Mozilla Public License 2.0 (MPL 2.0).$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Does ProcessWire support multiple languages?$q$, $q$Yes, native multi-language content and admin interface support is built into the ProcessWire core.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$What hosting does ProcessWire require?$q$, $q$ProcessWire runs on standard PHP hosting with a MySQL or MariaDB database, similar to most self-hosted CMS platforms.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$How many sites use ProcessWire?$q$, $q$Estimates cited around 2021 put ProcessWire usage at more than 5,000 developers worldwide with over 100,000 installations.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Are there paid add-ons for ProcessWire?$q$, $q$Yes, the creator offers optional paid Pro modules that add advanced functionality, though the core CMS remains free.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Custom-built business websites$q$, $q$Agencies and freelancers building fully custom, non-templated websites where design and data structure need full flexibility.$q$, $q$Web development agencies and freelance developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Multi-language content sites$q$, $q$Organizations needing native multi-language content management without relying on a heavy third-party plugin.$q$, $q$International businesses and organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Developer-controlled content APIs$q$, $q$Projects that need a lightweight, API-driven backend to power custom front ends or headless implementations.$q$, $q$Software developers building custom applications$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Core CMS/Framework$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source CMS and PHP framework","Fields-and-templates content model","Role-based access control","Native multi-language support","Community module directory"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$Pro Modules (optional)$q$, $q$Paid, per module$q$, $q$One-time or per-module purchase$q$, NULL, $q$["Advanced field types","Enhanced forms","Repeater and matrix fields","Additional developer tooling"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ProcessWire is a free, open-source content management system and PHP framework created by developer Ryan Cramer. It began as an internal tool at his web development company in 2003 and was publicly released as open-source software under the Mozilla Public License 2.0 in 2010.$q$, $q$Unlike consumer-facing CMS platforms, ProcessWire is built for developers: it exposes a clean PHP API, a flexible fields-and-templates content model, and a modular architecture, making it well suited to custom-built, non-templated websites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ProcessWire's core strengths include a flexible fields-and-templates data model rather than fixed content types, a well-documented PHP API for querying and manipulating content programmatically, and role-based access control for managing editor and administrator permissions.$q$, $q$The platform also includes native multi-language content support out of the box, a modular plugin architecture backed by an extensive community module directory, and a lightweight core that keeps sites fast without requiring heavy frameworks on top.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41d3c6d5-f1bd-4474-a701-bf4a104a118c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The ProcessWire core CMS and framework are entirely free to download and self-host, with no subscription fee, under the Mozilla Public License 2.0.$q$, $q$Ryan Cramer offers a small set of optional paid Pro modules that extend functionality, such as enhanced fields, forms, or repeaters, but these are optional purchases rather than a requirement for running the platform.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Project management$q$, $q$Manage RFIs, submittals, drawings, daily logs, and punch lists in one centralized system across office and field teams.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Financial management$q$, $q$Track budgets, contracts, change orders, and invoicing to keep project finances aligned with real-time progress.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Quality and safety management$q$, $q$Log inspections, safety observations, and incidents to support compliance and reduce jobsite risk.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Preconstruction tools$q$, $q$Estimating and bid management tools support project planning before construction begins.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Mobile field access$q$, $q$Field teams can access and update project data from mobile devices on the jobsite.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Unlimited users per contract$q$, $q$Pricing is based on construction volume rather than per-seat fees, so companies can add unlimited users.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$App Marketplace integrations$q$, $q$Connects with a broad ecosystem of third-party construction and accounting software.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Multi-language support$q$, $q$The web application supports numerous languages, including English, Spanish, French, German, and Portuguese.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Unlimited users included in pricing, encouraging full company-wide adoption$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Comprehensive coverage across project management, financials, and safety in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Large, established company with strong industry track record and global reach$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Broad marketplace of integrations with other construction and accounting tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Strong mobile field experience for on-site teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Pricing is not publicly disclosed and requires a sales conversation to obtain a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Pricing tied to Annual Construction Volume may be costly for very large contractors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Platform breadth can mean a learning curve for smaller teams that only need a subset of features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Annual contract model offers less flexibility than month-to-month SaaS pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$How much does Procore cost?$q$, $q$Procore does not publish fixed pricing. It charges an upfront annual fee per product based on the customer's Annual Construction Volume, and prospective customers must contact sales for a custom quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Does Procore charge per user?$q$, $q$No. Procore's pricing model includes unlimited users at no additional per-seat cost; fees are based on Annual Construction Volume instead.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$When was Procore founded?$q$, $q$Procore was founded in 2002 by Tooey Courtemanche.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Is Procore a public company?$q$, $q$Yes, Procore Technologies trades on the New York Stock Exchange under the ticker PCOR after its May 2021 IPO.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Where is Procore headquartered?$q$, $q$Procore is headquartered in Carpinteria, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$What types of companies use Procore?$q$, $q$Procore is used by owners, general contractors, and specialty/trade contractors across commercial, residential, industrial, and infrastructure construction.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Does Procore have a mobile app?$q$, $q$Yes, Procore offers mobile apps for field teams to access and update project data on the jobsite.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$What languages does Procore support?$q$, $q$Procore's web application supports numerous languages including English, Spanish, French, German, Portuguese, and more, with additional languages in ongoing rollout.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$General contractor project management$q$, $q$Coordinating RFIs, submittals, schedules, and daily logs across multiple active job sites.$q$, $q$General contractors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Owner project oversight$q$, $q$Giving project owners visibility into budgets, schedules, and quality across a construction portfolio.$q$, $q$Real estate owners and developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Specialty contractor field coordination$q$, $q$Managing safety, quality, and financial workflows for trade contractors working within larger projects.$q$, $q$Specialty and trade contractors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$Custom (quote-based)$q$, $q$Custom, based on Annual Construction Volume$q$, $q$Annual contract$q$, NULL, $q$["Unlimited users","Unlimited data storage","24/7 support included","Choice of product suite by business need","Optional multi-year and volume-based pricing"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Procore Technologies is a publicly traded (NYSE: PCOR) construction management software company founded in 2002 by Tooey Courtemanche and headquartered in Carpinteria, California. The platform connects owners, general contractors, and specialty contractors on a single system of record spanning project management, financials, quality and safety, and preconstruction.$q$, $q$Procore completed its IPO in May 2021 and has grown to serve more than 2 million users across over 150 countries, with roughly 4,400 employees as of 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Procore's core modules cover project management tools such as RFIs, submittals, drawing management, daily logs, and punch lists; financial management including budgeting, contracts, change orders, and invoicing; and quality and safety management for inspections, incident tracking, and safety observations.$q$, $q$The platform also supports preconstruction workflows like estimating and bid management, mobile field access for on-site teams, and a broad app marketplace of third-party integrations spanning accounting, scheduling, and design software.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bc3b8540-7633-45e3-8bb9-3540341f319d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Procore uses a custom, quote-based pricing model rather than published per-user tiers. Customers pay an upfront annual fee per product, based on their Annual Construction Volume (ACV), with unlimited users, unlimited data storage, and 24/7 support included at no extra cost.$q$, $q$Because pricing is not publicly listed, prospective customers must contact Procore's sales team for a customized estimate; options include annual contracts, multi-year pools, and volume protection.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Purchase requisitions and approvals$q$, $q$Employees submit purchase requests that route through configurable approval workflows before orders are placed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Purchase order management$q$, $q$Generate, track, and manage purchase orders throughout the procurement lifecycle.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Accounts payable automation$q$, $q$Automate invoice capture, three-way matching, and payment workflows as an add-on module.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Contract management$q$, $q$Centralize vendor contracts and key terms alongside purchasing and payables data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Expense and corporate card management$q$, $q$Manage employee expenses and corporate card spend within the same spend management system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Vendor management$q$, $q$Maintain vendor records and purchasing history to support supplier relationship management.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$No per-user pricing$q$, $q$Pricing is not charged strictly per user, supporting broader employee access to request purchases.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Modular add-ons$q$, $q$Organizations can start with the core purchasing platform and add modules as spend management needs grow.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Modular approach lets organizations pay only for the spend management functionality they need$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$No strict per-user pricing model encourages wider employee adoption of purchasing workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Positioned specifically for mid-sized organizations, avoiding unnecessary enterprise complexity$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Implementation does not require dedicated IT expertise$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Consolidates purchasing, AP, contracts, and card spend in one platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Pricing is not published and requires a sales conversation to obtain a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$One-time implementation fee adds to upfront cost beyond the subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Smaller company size compared to large enterprise procure-to-pay vendors like Coupa or SAP Ariba$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Full functionality depends on purchasing additional modules beyond the base platform$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$How much does Procurify cost?$q$, $q$Procurify does not publish fixed pricing. It offers flexible pricing based on features and support needs, and prospective customers must request a custom quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Does Procurify charge per user?$q$, $q$No, Procurify does not use a strict per-user pricing model, which is intended to support broader employee access to purchasing requests.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$When was Procurify founded?$q$, $q$Procurify was founded in 2012 by Kenneth Loi and Aman Mann.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Where is Procurify headquartered?$q$, $q$Procurify is headquartered in Vancouver, British Columbia, Canada.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$What modules does Procurify offer?$q$, $q$Procurify's core platform includes Purchasing, with optional add-on modules for Accounts Payable, Contracts, and Expense and Card management.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Is there an implementation fee?$q$, $q$Yes, Procurify charges a one-time implementation fee based on a customer's use cases and required integrations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$What size of company is Procurify best suited for?$q$, $q$Procurify is designed primarily for mid-sized organizations that have outgrown manual or spreadsheet-based purchasing but do not need a large enterprise procure-to-pay suite.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$How much funding has Procurify raised?$q$, $q$Procurify has raised approximately $82.5 million in funding across nine rounds.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Centralized purchase requisitions$q$, $q$Replacing spreadsheet-based purchase requests with structured, approval-routed requisitions.$q$, $q$Operations and finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Accounts payable automation$q$, $q$Automating invoice capture and matching to reduce manual AP processing time.$q$, $q$Finance and accounts payable teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Corporate card and expense control$q$, $q$Managing employee corporate card spend alongside purchasing and payables in one system.$q$, $q$Finance controllers and mid-sized organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Procurify Platform + Purchasing$q$, $q$Custom quote$q$, $q$Annual (typical)$q$, NULL, $q$["Purchase requisitions and approvals","Purchase order management","Vendor management","Base spend visibility"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$Add-on Modules$q$, $q$Custom quote$q$, $q$Annual (typical)$q$, NULL, $q$["Accounts Payable automation","Contract management","Expense and corporate card management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Procurify is a cloud-based spend management platform founded in 2012 by Kenneth Loi and Aman Mann and headquartered in Vancouver, Canada. It helps mid-sized organizations centralize purchasing, accounts payable, contracts, and corporate card spend in a single system rather than managing them across disconnected tools and spreadsheets.$q$, $q$The company has raised approximately $82.5 million in funding across nine rounds and employs roughly 150 to 180 people as of 2026, positioning it as a focused mid-market spend management vendor.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Procurify's base platform covers purchasing workflows including requisitions, purchase orders, approval routing, and vendor management, giving organizations visibility and control over spend requests before money leaves the company.$q$, $q$Additional modules extend the platform into accounts payable automation, contract management, and expense and corporate card management, allowing customers to consolidate multiple spend-related processes into one connected system as their needs grow.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c43b72a7-6804-4129-86f6-0b65715b2b9b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Procurify uses a custom, quote-based pricing model rather than publicly listed tiers, with flexible pricing based on the features and support level a customer needs rather than a strict per-user fee.$q$, $q$Customers typically start with the base Procurify Platform and Purchasing module, then add Accounts Payable, Contracts, or Expense and Card modules as needed; a one-time implementation fee applies based on use cases and required integrations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Modular product suite$q$, $q$Roadmaps, Ideas, and Feedback are separate modules that can be adopted individually or combined as needs grow.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Outcome-driven roadmapping$q$, $q$Roadmaps are built around strategic outcomes rather than simple feature-delivery timelines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Idea prioritization frameworks$q$, $q$Ideas can be scored and prioritized using frameworks like RICE to support objective decision-making.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Centralized customer feedback$q$, $q$Feedback from multiple channels is captured and linked directly to ideas and roadmap items.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Free reviewer accounts$q$, $q$Unlimited free contributor accounts let stakeholders add ideas and feedback without a paid editor seat.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Per-editor modular pricing$q$, $q$Organizations pay only for the modules and number of editors they actually need.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Annual billing discount$q$, $q$Annual subscriptions offer roughly 20 percent savings compared to monthly billing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Enterprise tier$q$, $q$A custom-priced Enterprise plan is available for large organizations needing additional security and support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Modular pricing lets teams pay only for the specific capabilities they need$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Unlimited free reviewer accounts support broad stakeholder participation without added cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Strong focus on outcome-driven, strategic roadmapping rather than just feature timelines$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Small, independently run company with a focused product vision$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Free trial with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Modular per-editor pricing can be harder to predict than a simple flat per-seat plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Smaller company size than larger competitors like Productboard may mean fewer resources for rapid feature development$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Costs can add up quickly for larger teams using all three modules$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Enterprise pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$How does ProdPad pricing work?$q$, $q$ProdPad prices its Roadmaps, Ideas, and Feedback modules separately on a per-editor basis, with Essentials and Advanced tiers for each module; customers pay only for the modules and editor seats they need.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$When was ProdPad founded?$q$, $q$ProdPad was founded in 2012 by Simon Cast and Janna Bastow.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Where is ProdPad headquartered?$q$, $q$ProdPad is headquartered in Brighton, England, United Kingdom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Does ProdPad offer a free trial?$q$, $q$Yes, ProdPad offers a free trial of at least seven days, with no credit card required to start.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$What is a ProdPad 'Reviewer' account?$q$, $q$Reviewer accounts are free, unlimited contributor accounts that let stakeholders add ideas and feedback without needing a paid editor seat.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Does ProdPad offer an annual billing discount?$q$, $q$Yes, annual billing typically offers around a 20 percent discount compared to monthly billing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Is there an Enterprise plan?$q$, $q$Yes, ProdPad Enterprise is a custom-priced tier for large organizations, available by contacting ProdPad's sales team.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$What modules does ProdPad offer?$q$, $q$ProdPad's platform is organized into three modules: Roadmaps, Ideas, and Feedback.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Strategic product roadmapping$q$, $q$Building outcome-focused roadmaps that communicate product strategy to stakeholders and executives.$q$, $q$Product managers and product leaders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Idea capture and prioritization$q$, $q$Collecting and scoring product ideas from internal teams and customers using structured frameworks.$q$, $q$Product teams and product ops$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Customer feedback management$q$, $q$Centralizing feedback from sales, support, and customers and linking it to roadmap decisions.$q$, $q$Product managers and customer-facing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Roadmaps Essentials$q$, $q$From $30/editor/month$q$, $q$Monthly or annual (20% off annually)$q$, NULL, $q$["Visual outcome-driven roadmaps","Unlimited free reviewer accounts","Core roadmap sharing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Roadmaps Advanced$q$, $q$From $55/editor/month$q$, $q$Monthly or annual (20% off annually)$q$, NULL, $q$["Advanced roadmap customization","Additional integrations","Expanded permissions"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Ideas and Feedback modules$q$, $q$From $30-45/editor/month per module$q$, $q$Monthly or annual (20% off annually)$q$, NULL, $q$["Idea prioritization frameworks","Centralized feedback collection","Linking feedback to roadmap items"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual$q$, NULL, $q$["Custom security and support terms","Multi-year discounts available","Dedicated account management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ProdPad is a modular product management platform founded in 2012 by Simon Cast and Janna Bastow and headquartered in Brighton, England. The platform is organized into three connected modules - Roadmaps, Ideas, and Feedback - that teams can adopt individually or together.$q$, $q$As a small, independently run company with roughly 11-50 employees, ProdPad positions itself as a focused, lean alternative to larger venture-backed product management platforms, emphasizing outcome-driven roadmapping over simple feature-delivery timelines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Roadmaps module lets teams build visual, strategy-led product roadmaps that communicate outcomes rather than just feature release dates, while the Ideas module supports capturing and prioritizing ideas using frameworks like RICE scoring.$q$, $q$The Feedback module centralizes customer feedback and requests, linking them to ideas and roadmap items so product decisions stay traceable to real customer input, and unlimited free 'Reviewer' accounts let stakeholders contribute without a paid seat.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f214525d-5b01-44d9-b029-88a13d27b4e6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ProdPad prices each module - Roadmaps, Ideas, and Feedback - separately at Essentials and Advanced tiers, with published per-editor rates starting around $24-30/month for Essentials and $45-55/month for Advanced, billed per editor rather than per total user.$q$, $q$Annual billing offers roughly a 20 percent discount versus monthly billing, unlimited free Reviewer accounts are included, and a custom-priced Enterprise tier is available for larger organizations via direct sales contact.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Interactive product tours$q$, $q$Guide new users through key product actions with step-by-step, no-code walkthroughs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Onboarding checklists$q$, $q$Track user progress through setup and activation steps with visual checklists.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Contextual hints and tooltips$q$, $q$Surface in-app guidance at the exact moment a user needs it, without overwhelming the interface.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$In-app help widget$q$, $q$Provide self-serve support content directly inside the product to reduce support ticket volume.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$User feedback collection$q$, $q$Gather user sentiment and feature requests directly within the product experience.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$AI Copilot$q$, $q$An AI-assisted feature that answers in-app user questions using the company's own content sources.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$User segmentation$q$, $q$Target tours, hints, and checklists to specific user segments based on behavior or attributes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$No-code editor$q$, $q$Build and edit onboarding flows without requiring developer involvement.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$No-code setup allows product and marketing teams to build onboarding without engineering resources$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Pricing is generally more accessible than larger enterprise digital adoption platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Combines tours, checklists, tooltips, help widget, and feedback in a single platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Includes AI Copilot functionality for automated in-app user support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Annual billing offers a meaningful 25 percent discount across all tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Pricing scales with monthly active users, which can raise costs quickly for high-traffic products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Business and Pro plans are listed at the same base monthly price, which can make tier selection less intuitive$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Company is comparatively young (founded 2019) with limited public information on funding or team size$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Custom/Enterprise pricing requires direct sales contact rather than transparent published rates$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$What does Product Fruits do?$q$, $q$Product Fruits is a no-code digital adoption platform for building in-app product tours, onboarding checklists, tooltips, help widgets, and feedback collection.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$How much does Product Fruits cost?$q$, $q$Plans start at $96/month for Starter, with Pro and Business plans at $149/month, all based on a 1,500 monthly active user baseline, with roughly 25% savings on annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$When was Product Fruits founded?$q$, $q$Product Fruits was founded in 2019.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Where is Product Fruits based?$q$, $q$Product Fruits is headquartered in Prague, Czech Republic.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Does Product Fruits require coding to set up?$q$, $q$No, Product Fruits is designed as a no-code platform so product, marketing, and customer success teams can build onboarding flows without engineering.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Does Product Fruits offer an AI feature?$q$, $q$Yes, Product Fruits includes an AI Copilot that can answer in-app user questions using a company's own content sources.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Is there a custom plan for larger companies?$q$, $q$Yes, Product Fruits offers a Custom plan with custom monthly active user limits, security reviews, and SLA agreements for larger organizations.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$How is Product Fruits pricing calculated?$q$, $q$Pricing is based on monthly active users (MAU) rather than internal team seats, since onboarding tools are typically shown to a company's full end-user base.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$SaaS user onboarding$q$, $q$Guiding new trial or free-tier users through key setup steps to improve activation and conversion.$q$, $q$SaaS product and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Feature adoption campaigns$q$, $q$Announcing and driving adoption of new features through targeted in-app tours and tooltips.$q$, $q$Product marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Self-serve support deflection$q$, $q$Reducing support ticket volume by surfacing contextual help and an AI Copilot inside the product.$q$, $q$Customer success and support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Starter$q$, $q$$96/month ($72/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["15 tours and guides","50 hints and tooltips","2 onboarding checklists","20 text conversations/month","3 team seats"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Pro$q$, $q$$149/month (~$112/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["100 tours and guides","500 hints and tooltips","Unlimited checklists","100 text conversations/month","10 team seats"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Business$q$, $q$$149/month (~$112/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited tours, hints, and checklists","400 text conversations/month","100 free voice conversation minutes/month","40 team seats","Contextual and voice onboarding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$Custom$q$, $q$Custom quote$q$, $q$Annual$q$, NULL, $q$["Custom monthly active user limits","Security audits","SLA agreements","Flexible contract terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Product Fruits is a no-code digital adoption platform founded in 2019 by Ladislav Salom and headquartered in Prague, Czech Republic. It helps SaaS companies build in-app product tours, onboarding checklists, tooltips, and feedback flows without requiring engineering resources.$q$, $q$The platform is aimed at improving trial-to-paid conversion, speeding up new-user time-to-value, and reducing support ticket volume through proactive, self-serve in-app guidance.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include interactive product tours and walkthroughs, onboarding checklists that track user progress, contextual hints and tooltips, and an in-app help widget for surfacing support content directly inside the product.$q$, $q$Product Fruits also includes a feedback collection module for gathering user sentiment and requests, plus newer AI-assisted features like a Copilot that can answer in-app user questions using a company's own content sources.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('af388462-725e-429b-a572-58a70a2238c4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Product Fruits prices its Starter, Pro, and Business plans starting at $96, $149, and $149 per month respectively (with roughly 25 percent savings on annual billing), based on a baseline of 1,500 monthly active users, with pricing scaling as MAU grows.$q$, $q$A Custom plan is available for larger organizations that need higher MAU limits, dedicated security reviews, and formal SLA agreements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('af388462-725e-429b-a572-58a70a2238c4', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Centralized feedback inbox$q$, $q$Aggregate customer and prospect feedback from support tickets, sales calls, surveys, and other channels in one place.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Feature scoring and prioritization$q$, $q$Score and rank features against customer impact and strategic objectives to guide roadmap decisions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Visual roadmap building$q$, $q$Build and share timeline-based or now-next-later roadmaps tailored to different stakeholder audiences.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Public product portals$q$, $q$Share external-facing roadmaps and collect feedback directly from customers through a branded portal.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Spark AI features$q$, $q$AI-assisted feedback summarization, insight generation, and prioritization support built into the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Customer segmentation$q$, $q$Segment feedback and prioritization by customer type, plan tier, or other attributes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Integrations$q$, $q$Connect with tools like Salesforce, Jira, Slack, and Zendesk to sync feedback and roadmap data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Teamspaces and permissions$q$, $q$Organize work into teamspaces with role-based access for different product teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Strong customer-feedback-to-roadmap workflow purpose-built for product teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Free plan available with real functionality, including limited AI features$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Well-funded, established company with a large user base and strong integration ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$AI-powered Spark features help speed up feedback analysis and prioritization$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Flexible per-maker pricing that keeps viewer and contributor access free on higher tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Per-maker pricing can become expensive as more product managers and stakeholders need edit access$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Business plan requires a minimum of two makers and Enterprise requires a minimum of five$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$AI credit-based system adds complexity to understanding total cost at scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Full enterprise-grade features (SSO, SCIM, custom roles) are reserved for the highest, custom-priced tier$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Is Productboard free?$q$, $q$Yes, Productboard offers a Free plan with unlimited roadmaps, 500 feedback notes, 25 contributors, and 50 AI credits per month, with no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$How much does Productboard cost?$q$, $q$Paid plans start at $19/maker/month for Plus (annual billing), $59/maker/month for Business (minimum two makers), and custom Enterprise pricing with a minimum of five makers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$When was Productboard founded?$q$, $q$Productboard was founded in 2014 by Hubert Palan and Daniel Hejl.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Where is Productboard headquartered?$q$, $q$Productboard is dual-headquartered in San Francisco, California, and Prague, Czech Republic, with additional offices in Vancouver, Dublin, London, and Brno.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$What is Spark in Productboard?$q$, $q$Spark is Productboard's AI feature set that helps summarize feedback, generate insights, and support prioritization decisions using a credit-based system.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$How much funding has Productboard raised?$q$, $q$Productboard has raised approximately $261.7 million in total funding across seven rounds, including a $125 million Series D in 2022.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Does Productboard offer a free trial?$q$, $q$Yes, a 14-day free trial is available on the Business plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$What is a 'maker' seat in Productboard pricing?$q$, $q$A maker is a paid seat for someone actively creating or managing product plans; contributor and viewer access is included at no extra cost depending on the plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Customer feedback aggregation$q$, $q$Centralizing feedback from support, sales, and surveys into a single system tied to roadmap decisions.$q$, $q$Product managers and product ops teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Feature prioritization$q$, $q$Scoring and ranking competing feature requests against customer impact and strategic goals.$q$, $q$Product management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Roadmap communication$q$, $q$Sharing internal and external-facing roadmaps to align engineering, sales, and customers.$q$, $q$Product leaders and cross-functional stakeholders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Free$q$, $q$$0/month$q$, $q$N/A$q$, NULL, $q$["50 AI credits/month","Unlimited roadmaps","500 feedback notes","25 contributors","1 teamspace and product portal"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Plus$q$, $q$$19/maker/month (annual) or $25/maker/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["250 AI credits/maker/month","Customer segmentation","Feedback loop closing","Product usage integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Business$q$, $q$$59/maker/month (annual, min. 2 makers) or $75/maker/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["500 AI credits/maker/month","Unlimited feedback notes and teamspaces","Shared skills library","2 product portals","Enhanced customization"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$Enterprise$q$, $q$Custom quote (min. 5 makers, annual)$q$, $q$Annual$q$, NULL, $q$["800 AI credits/maker/month","Unlimited contributors","SAML SSO and SCIM provisioning","Custom roles","Salesforce integration and live onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Productboard is a customer-driven product management platform founded in 2014 by Hubert Palan and Daniel Hejl, with dual headquarters in San Francisco and Prague. The platform helps product teams capture customer feedback, prioritize features against strategic goals, and build shareable roadmaps.$q$, $q$The company has raised approximately $261.7 million in total funding, reached a $1.7 billion valuation in its 2022 Series D round, and employs roughly 330-340 people as of recent estimates.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Productboard centralizes customer feedback from multiple channels into a single inbox, then uses a scoring and prioritization engine to help teams weigh features against customer impact and business objectives.$q$, $q$The platform includes visual roadmap building and sharing tools, including public-facing product portals, along with integrations to tools like Salesforce, Jira, Slack, and Zendesk, plus an AI feature called Spark for summarizing feedback and supporting prioritization decisions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44247eb4-4fad-4252-a448-315159706699', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Productboard offers a Free plan with core roadmapping and limited AI credits, a Plus plan from $19/maker/month (annual billing), a Business plan from $59/maker/month (annual billing, minimum two makers), and a custom-priced Enterprise plan with a minimum of five makers.$q$, $q$Annual billing saves roughly 21 percent versus monthly billing, a 14-day free trial is available on the Business plan, and additional AI credit top-ups can be purchased if a team exceeds its plan's monthly allotment.$q$]::text[], 2);
